// // This module implements a 5-bit wide 1-to-2 multiplexer. When the select signal 'sel' is 0, the output 'c' will equal the input 'a', and when 'sel' is 1, the output 'c' will equal the input 'b'.
module top_module(
	    input [4:0] a,
        input [4:0] b,
        input sel,
        output [4:0] c
	);assign c = sel ? a:b;

endmodule
